// =============================================================================
// SECTION 1 — Value: scalar autograd engine (replaces the Python Value class)
// =============================================================================

use std::cell::RefCell;
use std::collections::HashSet;
use std::fmt;
use std::rc::Rc;

/// Internal mutable state of a single scalar node in the computation graph.
struct ValueInner {
    data: f64,
    grad: f64,
    label: String,
    op: String,
    prev: Vec<Value>,
    backward_fn: Option<Box<dyn Fn()>>,
}

/// A reference-counted, interior-mutable scalar value with autograd support.
/// This is the direct equivalent of the Python `Value` class.
#[derive(Clone)]
pub struct Value(Rc<RefCell<ValueInner>>);

impl Value {
    // ------------------------------------------------------------------
    // Constructor
    // ------------------------------------------------------------------
    pub fn new(data: f64) -> Self {
        Value(Rc::new(RefCell::new(ValueInner {
            data,
            grad: 0.0,
            label: String::new(),
            op: String::new(),
            prev: vec![],
            backward_fn: None,
        })))
    }

    pub fn with_label(data: f64, label: &str) -> Self {
        let v = Self::new(data);
        v.set_label(label);
        v
    }

    // ------------------------------------------------------------------
    // Accessors
    // ------------------------------------------------------------------
    pub fn data(&self) -> f64 {
        self.0.borrow().data
    }

    pub fn grad(&self) -> f64 {
        self.0.borrow().grad
    }

    pub fn set_data(&self, d: f64) {
        self.0.borrow_mut().data = d;
    }

    pub fn set_grad(&self, g: f64) {
        self.0.borrow_mut().grad = g;
    }

    pub fn set_label(&self, l: &str) {
        self.0.borrow_mut().label = l.to_string();
    }

    pub fn label(&self) -> String {
        self.0.borrow().label.clone()
    }

    // Used so HashSet can identify nodes by pointer identity (same as Python id())
    fn ptr_id(&self) -> usize {
        Rc::as_ptr(&self.0) as usize
    }

    // ------------------------------------------------------------------
    // Arithmetic operations  (mirrors __add__, __mul__, __pow__, etc.)
    // ------------------------------------------------------------------

    /// Addition:  self + other
    pub fn add(&self, other: &Value) -> Value {
        let out = Value::new(self.data() + other.data());
        out.0.borrow_mut().op = "+".into();
        out.0.borrow_mut().prev = vec![self.clone(), other.clone()];

        let s = self.clone();
        let o = other.clone();
        let out_ref = out.clone();
        out.0.borrow_mut().backward_fn = Some(Box::new(move || {
            let og = out_ref.grad();
            s.0.borrow_mut().grad += og;
            o.0.borrow_mut().grad += og;
        }));
        out
    }

    /// Multiplication: self * other
    pub fn mul(&self, other: &Value) -> Value {
        let out = Value::new(self.data() * other.data());
        out.0.borrow_mut().op = "*".into();
        out.0.borrow_mut().prev = vec![self.clone(), other.clone()];

        let s = self.clone();
        let o = other.clone();
        let out_ref = out.clone();
        out.0.borrow_mut().backward_fn = Some(Box::new(move || {
            let og = out_ref.grad();
            s.0.borrow_mut().grad += o.data() * og;
            o.0.borrow_mut().grad += s.data() * og;
        }));
        out
    }

    /// Power: self ^ exp  (integer or float exponent)
    pub fn pow(&self, exp: f64) -> Value {
        let out = Value::new(self.data().powf(exp));
        out.0.borrow_mut().op = format!("**{}", exp);
        out.0.borrow_mut().prev = vec![self.clone()];

        let s = self.clone();
        let out_ref = out.clone();
        out.0.borrow_mut().backward_fn = Some(Box::new(move || {
            let og = out_ref.grad();
            s.0.borrow_mut().grad += exp * s.data().powf(exp - 1.0) * og;
        }));
        out
    }

    /// Negation: -self
    pub fn neg(&self) -> Value {
        self.mul(&Value::new(-1.0))
    }

    /// Subtraction: self - other
    pub fn sub(&self, other: &Value) -> Value {
        self.add(&other.neg())
    }

    /// Division: self / other  ==  self * other^(-1)
    pub fn div(&self, other: &Value) -> Value {
        self.mul(&other.pow(-1.0))
    }

    /// Scalar addition:  self + scalar
    pub fn add_f64(&self, scalar: f64) -> Value {
        self.add(&Value::new(scalar))
    }

    /// Scalar multiplication: self * scalar
    pub fn mul_f64(&self, scalar: f64) -> Value {
        self.mul(&Value::new(scalar))
    }

    // ------------------------------------------------------------------
    // Activation functions
    // ------------------------------------------------------------------

    /// Hyperbolic tangent activation (tanh)
    pub fn tanh(&self) -> Value {
        let x = self.data();
        let t = (2.0 * x).exp();
        let t = (t - 1.0) / (t + 1.0);
        let out = Value::new(t);
        out.0.borrow_mut().op = "tanh".into();
        out.0.borrow_mut().prev = vec![self.clone()];

        let s = self.clone();
        let out_ref = out.clone();
        out.0.borrow_mut().backward_fn = Some(Box::new(move || {
            let og = out_ref.grad();
            // t is captured by value because it is Copy (f64)
            s.0.borrow_mut().grad += (1.0 - t * t) * og;
        }));
        out
    }

    // ------------------------------------------------------------------
    // Backpropagation
    // ------------------------------------------------------------------

    /// Runs backprop from this node back through the full computation graph.
    /// Equivalent to Python's `Value.backward()`.
    pub fn backward(&self) {
        // 1. Build topological order
        let mut topo: Vec<Value> = vec![];
        let mut visited: HashSet<usize> = HashSet::new();

        fn build_topo(v: &Value, topo: &mut Vec<Value>, visited: &mut HashSet<usize>) {
            let id = v.ptr_id();
            if !visited.contains(&id) {
                visited.insert(id);
                let children = v.0.borrow().prev.clone();
                for child in &children {
                    build_topo(child, topo, visited);
                }
                topo.push(v.clone());
            }
        }

        build_topo(self, &mut topo, &mut visited);

        // 2. Seed gradient at the root
        self.set_grad(1.0);

        // 3. Walk in reverse topological order, calling each node's backward closure
        for node in topo.iter().rev() {
            let bfn = node.0.borrow_mut().backward_fn.take();
            if let Some(f) = bfn {
                f();
                // Put it back so the graph can be reused
                node.0.borrow_mut().backward_fn = Some(f);
            }
        }
    }
}

impl fmt::Display for Value {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "Value(data={}, grad={})", self.data(), self.grad())
    }
}

// =============================================================================
// SECTION 2 — Neural network primitives (Neuron, Layer, MLP)
//             Equivalent to the Python Neuron / Layer / MLP classes.
// =============================================================================

use rand::Rng;

/// A single neuron: stores weights + bias, computes tanh(w·x + b).
pub struct Neuron {
    pub w: Vec<Value>,
    pub b: Value,
}

impl Neuron {
    pub fn new(nin: usize) -> Self {
        let mut rng = rand::thread_rng();
        let w = (0..nin)
            .map(|_| Value::new(rng.gen_range(-1.0..=1.0)))
            .collect();
        let b = Value::new(rng.gen_range(-1.0..=1.0));
        Neuron { w, b }
    }

    /// Forward pass: tanh( sum(wi * xi) + b )
    pub fn call(&self, x: &[Value]) -> Value {
        let act = self
            .w
            .iter()
            .zip(x.iter())
            .map(|(wi, xi)| wi.mul(xi))
            .fold(self.b.clone(), |acc, v| acc.add(&v));
        act.tanh()
    }

    /// Returns all learnable parameters (weights + bias).
    pub fn parameters(&self) -> Vec<Value> {
        let mut params = self.w.clone();
        params.push(self.b.clone());
        params
    }
}

/// A fully-connected layer of neurons.
pub struct Layer {
    pub neurons: Vec<Neuron>,
}

impl Layer {
    pub fn new(nin: usize, nout: usize) -> Self {
        Layer {
            neurons: (0..nout).map(|_| Neuron::new(nin)).collect(),
        }
    }

    /// Forward pass through every neuron in the layer.
    /// Returns a `Vec<Value>` — always consistent, no ambiguous union type.
    pub fn call(&self, x: &[Value]) -> Vec<Value> {
        self.neurons.iter().map(|n| n.call(x)).collect()
    }

    pub fn parameters(&self) -> Vec<Value> {
        self.neurons.iter().flat_map(|n| n.parameters()).collect()
    }
}

/// Multi-layer perceptron: a stack of `Layer`s.
pub struct MLP {
    pub layers: Vec<Layer>,
}

impl MLP {
    /// `nin` — number of inputs.
    /// `nouts` — list of layer sizes, e.g. `vec![4, 4, 1]`.
    pub fn new(nin: usize, nouts: &[usize]) -> Self {
        let sizes: Vec<usize> = std::iter::once(nin).chain(nouts.iter().cloned()).collect();
        let layers = sizes
            .windows(2)
            .map(|w| Layer::new(w[0], w[1]))
            .collect();
        MLP { layers }
    }

    /// Forward pass through all layers; returns the final layer's outputs.
    /// For a single-output MLP the Vec will have exactly one element.
    pub fn call(&self, x: &[Value]) -> Vec<Value> {
        let mut out: Vec<Value> = x.to_vec();
        for layer in &self.layers {
            out = layer.call(&out);
        }
        out
    }

    pub fn parameters(&self) -> Vec<Value> {
        self.layers.iter().flat_map(|l| l.parameters()).collect()
    }
}

// =============================================================================
// SECTION 3 — Loss, gradient descent, training loop
// =============================================================================

/// Mean-squared-error loss over a batch.
/// Equivalent to:  loss = sum((yout - ygt)**2 for ygt, yout in zip(ys, ypred))
pub fn mse_loss(ypred: &[Value], ytrue: &[f64]) -> Value {
    ypred
        .iter()
        .zip(ytrue.iter())
        .map(|(yout, &ygt)| yout.sub(&Value::new(ygt)).pow(2.0))
        .fold(Value::new(0.0), |acc, v| acc.add(&v))
}

/// Zero all parameter gradients before a new backward pass.
pub fn zero_grad(params: &[Value]) {
    for p in params {
        p.set_grad(0.0);
    }
}

/// Gradient descent update step:  p.data -= lr * p.grad
pub fn sgd_step(params: &[Value], lr: f64) {
    for p in params {
        let update = p.data() - lr * p.grad();
        p.set_data(update);
    }
}

// =============================================================================
// SECTION 4 — PyTorch equivalent using the Burn crate
//             Mirrors the `import torch` section of the original Python file.
