// NOTE: To compile this section, add to Cargo.toml:
//   burn = { version = "0.13", features = ["ndarray"] }

use burn::backend::NdArray;
use burn::tensor::{Tensor, backend::Backend};
use burn::nn::{Linear, LinearConfig};
use burn::nn::loss::MseLoss;
use burn::nn::loss::Reduction;

type B = NdArray<f64>;

/// Replicates the single-neuron forward + backward check that was done with
/// PyTorch in the original Python file.
///
/// Inputs:  x1=2.0, x2=0.0
/// Weights: w1=-3.0, w2=1.0
/// Bias:    b=6.8813735870195432
/// Output:  tanh(w1*x1 + w2*x2 + b)
pub fn burn_single_neuron_check() {
    // Build tensors — shape [1] for each scalar, requires_grad handled by Burn's autodiff.
    // Burn's NdArray backend does not yet expose per-tensor grad control at the scalar
    // level the same way PyTorch does, so we demonstrate the forward pass and note where
    // gradients would be read back in a full autodiff backend (e.g. burn::backend::Autodiff<NdArray>).

    let device = burn::backend::ndarray::NdArrayDevice::Cpu;

    let x1: Tensor<B, 1> = Tensor::from_floats([2.0_f64], &device);
    let x2: Tensor<B, 1> = Tensor::from_floats([0.0_f64], &device);
    let w1: Tensor<B, 1> = Tensor::from_floats([-3.0_f64], &device);
    let w2: Tensor<B, 1> = Tensor::from_floats([1.0_f64], &device);
    let b:  Tensor<B, 1> = Tensor::from_floats([6.881_373_587_019_543_f64], &device);

    let n = w1 * x1 + w2 * x2 + b;
    let o = n.tanh();

    println!("[Burn] Single neuron output: {:?}", o.to_data());
    // Expected: ~0.7071  (matches Python/PyTorch output)
}

// =============================================================================
// SECTION 5 — Optional plot helper (replaces matplotlib)
//             Uses the `plotters` crate to render tanh curve to an SVG file.
// =============================================================================

#[cfg(feature = "plot")]
pub fn plot_tanh() -> Result<(), Box<dyn std::error::Error>> {
    use plotters::prelude::*;
    let root = SVGBackend::new("tanh_curve.svg", (640, 480)).into_drawing_area();
    root.fill(&WHITE)?;
    let mut chart = ChartBuilder::on(&root)
        .caption("tanh activation", ("sans-serif", 30))
        .margin(20)
        .x_label_area_size(30)
        .y_label_area_size(30)
        .build_cartesian_2d(-5.0_f64..5.0_f64, -1.2_f64..1.2_f64)?;
    chart.configure_mesh().draw()?;
    chart.draw_series(LineSeries::new(
        (-500..=500).map(|x| {
            let xf = x as f64 / 100.0;
            (xf, xf.tanh())
        }),
        &RED,
    ))?;
    root.present()?;
    println!("Saved tanh_curve.svg");
    Ok(())
}

// =============================================================================
// SECTION 6 — main()  (ties everything together, mirrors the Python script body)
// =============================================================================

fn main() {
    // ---------------------------------------------------------------
    // 6a. Evaluate the quadratic  f(x) = 3x² - 4x + 5  at x=3
    // ---------------------------------------------------------------
    let f = |x: f64| 3.0 * x * x - 4.0 * x + 5.0;
    println!("f(3.0) = {}", f(3.0));  // expected: 20.0

    // ---------------------------------------------------------------
    // 6b. Numerical derivative of f at x = 2/3
    // ---------------------------------------------------------------
    let h = 1e-8_f64;
    let x = 2.0 / 3.0;
    let slope = (f(x + h) - f(x)) / h;
    println!("f'(2/3) ≈ {:.6}", slope);  // expected: 0.0 (minimum of f)

    // ---------------------------------------------------------------
    // 6c. Manual gradient for  y = a*b + c   w.r.t. c
    // ---------------------------------------------------------------
    let a = 2.0_f64;
    let b = -3.0_f64;
    let c = 10.0_f64;
    let y  = a * b + c;
    let y1 = a * b + (c + h);
    let grad_c = (y1 - y) / h;
    println!("dy/dc = {:.6}", grad_c);  // expected: 1.0

    // ---------------------------------------------------------------
    // 6d. Build the computation graph and run backprop
    //     L = g * (a + b*c)  — same graph as the Python walkthrough
    // ---------------------------------------------------------------
    let va = Value::with_label(2.0,  "a");
    let vb = Value::with_label(-3.0, "b");
    let vc = Value::with_label(10.0, "c");
    let vg = Value::with_label(-2.0, "g");

    let e = vb.mul(&vc);   e.set_label("e");
    let d = va.add(&e);    d.set_label("d");
    let l = vg.mul(&d);    l.set_label("L");

    l.backward();

    println!("\n--- Autograd gradients ---");
    println!("a.grad = {:.4}  (expected  -2.0)", va.grad());
    println!("b.grad = {:.4}  (expected -20.0)", vb.grad());
    println!("c.grad = {:.4}  (expected   6.0)", vc.grad());
    println!("g.grad = {:.4}  (expected -28.0)", vg.grad());

    // ---------------------------------------------------------------
    // 6e. Single neuron with tanh  (replicates the Python walkthrough)
    //     x1=2, x2=0, w1=-3, w2=1, b=6.88137…  → o ≈ 0.7071
    // ---------------------------------------------------------------
    let x1 = Value::with_label(2.0,  "x1");
    let x2 = Value::with_label(0.0,  "x2");
    let w1 = Value::with_label(-3.0, "w1");
    let w2 = Value::with_label(1.0,  "w2");
    let bias = Value::with_label(6.881_373_587_019_543, "b");

    let x1w1   = x1.mul(&w1);   x1w1.set_label("x1w1");
    let x2w2   = x2.mul(&w2);   x2w2.set_label("x2w2");
    let sum_xw = x1w1.add(&x2w2); sum_xw.set_label("x1w1+x2w2");
    let n      = sum_xw.add(&bias); n.set_label("n");
    let o      = n.tanh();           o.set_label("o");

    o.backward();

    println!("\n--- Single neuron (tanh) ---");
    println!("o    = {:.6}  (expected ≈ 0.707107)", o.data());
    println!("x1.grad = {:.4}  (expected -1.5)", x1.grad());
    println!("w1.grad = {:.4}  (expected  1.0)", w1.grad());
    println!("x2.grad = {:.4}  (expected  0.5)", x2.grad());
    println!("w2.grad = {:.4}  (expected  0.0)", w2.grad());

    // ---------------------------------------------------------------
    // 6f. Burn crate equivalent of the PyTorch single-neuron check
    // ---------------------------------------------------------------
    println!("\n--- Burn single-neuron check ---");
    burn_single_neuron_check();

    // ---------------------------------------------------------------
    // 6g. Build MLP and train for 20 steps
    //     Architecture: 3 inputs → [4, 4, 1]
    //     Dataset: 4 samples, binary targets  [1, -1, -1, 1]
    // ---------------------------------------------------------------
    let mlp = MLP::new(3, &[4, 4, 1]);

    let xs: Vec<Vec<Value>> = vec![
        vec![Value::new(2.0),  Value::new(3.0),  Value::new(-1.0)],
        vec![Value::new(3.0),  Value::new(-1.0), Value::new(0.5)],
        vec![Value::new(0.5),  Value::new(1.0),  Value::new(1.0)],
        vec![Value::new(1.0),  Value::new(1.0),  Value::new(-1.0)],
    ];
    let ys: Vec<f64> = vec![1.0, -1.0, -1.0, 1.0];

    println!("\n--- MLP training (20 steps, lr=0.05) ---");
    for k in 0..20 {
        // Forward pass — unwrap the single output per sample
        let ypred: Vec<Value> = xs
            .iter()
            .map(|x| mlp.call(x).into_iter().next().unwrap())
            .collect();

        // Loss
        let loss = mse_loss(&ypred, &ys);

        // Backward pass
        let params = mlp.parameters();
        zero_grad(&params);
        loss.backward();

        // SGD update
        sgd_step(&params, 0.05);

        println!("step {:2}  loss = {:.6}", k, loss.data());
    }

    // ---------------------------------------------------------------
    // 6h. Per-sample losses after training
    // ---------------------------------------------------------------
    let ypred_final: Vec<Value> = xs
        .iter()
        .map(|x| mlp.call(x).into_iter().next().unwrap())
        .collect();

    println!("\n--- Per-sample squared errors after training ---");
    for (i, (yout, &ygt)) in ypred_final.iter().zip(ys.iter()).enumerate() {
        let err = yout.sub(&Value::new(ygt)).pow(2.0);
        println!("sample {}: pred={:.4}  target={:.1}  err²={:.6}",
            i, yout.data(), ygt, err.data());
    }

    // ---------------------------------------------------------------
    // 6i. Optional: render tanh curve  (requires `--features plot`)
    // ---------------------------------------------------------------
    #[cfg(feature = "plot")]
    plot_tanh().expect("plot failed");
}
